#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

void solve() {
    string s, t;
    cin >> s >> t;

    int n = s.size();
    vector<int> zero_blocks, one_blocks;

    // Find blocks of '0' and '1'
    for (int i = 0; i < n; ++i) {
        if ((i == 0 || s[i] != s[i-1]) && s[i] == '0') {
            int j = i;
            while (j + 1 < n && s[j+1] == '0') ++j;
            zero_blocks.push_back(j - i + 1);
            i = j;
        } else if ((i == 0 || s[i] != s[i-1]) && s[i] == '1') {
            int j = i;
            while (j + 1 < n && s[j+1] == '1') ++j;
            one_blocks.push_back(j - i + 1);
            i = j;
        }
    }

    int total_zeros = 0, total_ones = 0;
    for (int x : zero_blocks) total_zeros += x;
    for (int x : one_blocks) total_ones += x;

    int target_zeros = 0, target_ones = 0;
    for (char c : t) {
        if (c == '0') ++target_zeros;
        else if (c == '1') ++target_ones;
    }

    if (total_zeros != target_zeros || total_ones != target_ones) {
        cout << "-1\n";
        return;
    }

    // Greedily assign blocks to positions
    int ops = 0;
    for (int i = 0; i < n; ++i) {
        char c = t[i];
        if (c == '0') {
            if (!zero_blocks.empty()) {
                zero_blocks.pop_back();
            } else {
                cout << "-1\n";
                return;
            }
        } else if (c == '1') {
            if (!one_blocks.empty()) {
                one_blocks.pop_back();
            } else {
                cout << "-1\n";
                return;
            }
        }
    }

    cout << ops << "\n";
}

int main() {
    ios::sync_with_stdio(false); cin.tie(0);
    int t;
    cin >> t;
    while (t--) solve();
    return 0;
}

