#include <bits/stdc++.h>
using namespace std;

#define FAST_IO ios_base::sync_with_stdio(false); cin.tie(nullptr); cout.tie(nullptr);
const int MAXN = 2e5 + 5;

vector<int> adj[MAXN];
int n, m, p, b;
int tokens[MAXN], bonuses[MAXN];

bool bfs(int start) {
    vector<bool> visited(n + 1, false);
    visited[start] = true;
    queue<pair<int, int>> q;
    q.push({start, 0});

    while (!q.empty()) {
        auto [current, moves] = q.front();
        q.pop();

        if (current == 1) return true;

        for (int neighbor : adj[current]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                q.push({neighbor, moves + 1});

                // Check if neighbor is a bonus
                for (int i = 0; i < b; ++i) {
                    if (bonuses[i] == neighbor) {
                        for (int adj_neighbor : adj[neighbor]) {
                            if (!visited[adj_neighbor]) {
                                visited[adj_neighbor] = true;
                                q.push({adj_neighbor, moves + 1});
                            }
                        }
                        break;
                    }
                }
            }
        }
    }
    return false;
}

void solve() {
    cin >> n >> m >> p >> b;

    for (int i = 0; i < p; ++i) {
        cin >> tokens[i];
    }

    for (int i = 0; i < b; ++i) {
        cin >> bonuses[i];
    }

    for (int i = 0; i < m; ++i) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    bool possible = false;
    for (int i = 0; i < p; ++i) {
        if (tokens[i] == 1 || bfs(tokens[i])) {
            possible = true;
            break;
        }
    }

    if (possible) {
        cout << "YES\n";
    } else {
        cout << "NO\n";
    }
}

int main() {
    FAST_IO;
    int t;
    cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

