#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

const int MOD = 1000000007;

int solve(int n, int k) {
    vector<vector<int>> dp(1 << k, vector<int>(n + 1, 0));
    dp[0][0] = 1;

    for (int j = 1; j <= n; ++j) {
        vector<vector<int>> new_dp(1 << k, vector<int>(n + 1, 0));
        for (int mask = 0; mask < (1 << k); ++mask) {
            for (int i = 0; i < k; ++i) {
                if ((mask & (1 << i)) == 0) {
                    new_dp[mask | (1 << i)][j] = (new_dp[mask | (1 << i)][j] + dp[mask][j - 1]) % MOD;
                } else {
                    for (int sub_mask = 0; sub_mask < (1 << k); ++sub_mask) {
                        if ((sub_mask & (1 << i)) == 0) {
                            new_dp[sub_mask][j] = (new_dp[sub_mask][j] + dp[mask][j - 1]) % MOD;
                        }
                    }
                }
            }
        }
        swap(dp, new_dp);
    }

    int result = 0;
    for (int mask = 0; mask < (1 << k); ++mask) {
        result = (result + dp[mask][n]) % MOD;
    }
    return result;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n, k;
        cin >> n >> k;
        cout << solve(n, k) << '\n';
    }

    return 0;
}

