const int N = 100010;

vector<int> u(N, -1);
vector<vector<int>> divi(N);
vector<vector<int>> pd(N);
vector<int> mark(N, 0);
vector<bool> has(N, false);
vector<int> cnt(N, 0);

void precalc() {
    for (int i = 1; i < N; ++i) {
        for (int j = i; j < N; j += i) {
            divi[j].pb(i);
        }
    }
    for (int i = 2; i < N; ++i) {
        if (mark[i] == 1) continue;
        for (int j = i; j < N; j += i) {
            pd[j].pb(i);
            mark[j] = 1;
        }
    }
    for (int i = 1; i < N; ++i) {
        for (int prm : pd[i]) {
            int time = 0;
            int _i = i;
            while (_i % prm == 0) {
                ++time;
                _i /= prm;
            }
            if (time > 1) {
                u[i] = 0;
                break;
            }
        }
        if (u[i] == -1) {
            if (pd[i].size() & 1) u[i] = -1;
            else                  u[i] = 1;
        }
    }
}

int has_coprime(int n) {
    int ret = 0;
    for (int d : divi[n]) {
        ret += u[d] * cnt[d];
    }
    return ret;
}

void update(int n, int val) {
    for (int d : divi[n]) {
        cnt[d] += val;
    }
}

void solve() {
    int n;
    cin >> n;
    vector<int> li(n);
    for (int i = 0; i < n; ++i) {
        cin >> li[i];
    }

    ll ans = 0;
    for (int i = 0; i < n; ++i) {
        if (has[li[i]]) {
            ans = max(ans, (ll)li[i]);
        }
        has[li[i]] = true;
    }

    for (int g = 1; g < N; ++g) {
        vector<int> st;
        int max_num = N / g;
        for (int num = max_num; num >= 1; --num) {
            int val = num * g;
            if (val >= N || !has[val]) continue;

            int how_many = has_coprime(num);
            while (how_many > 0) {
                int now = st.back(); st.pob();
                if (gcd(now, num) == 1) {
                    ans = max(ans, 1LL * num * now * g);
                    --how_many;
                }
                update(now, -1);
            }
            st.pb(num);
            update(num, 1);
        }
        while (!st.empty()) {
            update(st.back(), -1);
            st.pob();
        }
    }
    cout << ans << endl;
}

int main() {
    fastio;
    precalc();
    int t = 1;
    while (cin >> t) {
        solve();
    }
    return 0;
}

