#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

#define MAXN 100005

vector<int> spf(MAXN);

void sieve() {
    for (int i = 2; i < MAXN; ++i) spf[i] = i;
    for (int i = 2; i * i < MAXN; ++i) {
        if (spf[i] == i) {
            for (int j = i * i; j < MAXN; j += i) {
                if (spf[j] > i) spf[j] = i;
            }
        }
    }
}

long long gcd(long long a, long long b) {
    while (b != 0) {
        long long t = b;
        b = a % b;
        a = t;
    }
    return a;
}

long long lcm(long long x, long long y) {
    return abs(x * y) / gcd(x, y);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    sieve();

    long long max_lcm = 0;
    for (int i = 0; i < n; ++i) {
        long long current = a[i];
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_lcm = max(max_lcm, lcm(current, a[j]));
        }
    }

    cout << max_lcm << endl;

    return 0;
}

