void solve(int n, int k, const vector<int>& a) {
    vector<bool> covered(k + 1, false);
    set<int> primes;

    // Function to mark multiples of p up to k
    auto mark_multiples = [&](int p) {
        for (int i = p; i <= k; i += p) {
            covered[i] = true;
        }
    };

    // Extract prime factors and mark multiples
    for (int x : a) {
        for (int f = 2; f * f <= x; ++f) {
            while (x % f == 0) {
                primes.insert(f);
                mark_multiples(f);
                x /= f;
            }
        }
        if (x > 1) {
            primes.insert(x);
            mark_multiples(x);
        }
    }

    // Collect uncovered multiples
    vector<int> missing;
    for (int i = 1; i <= k; ++i) {
        if (!covered[i]) {
            missing.push_back(i);
        }
    }

    // Output result
    if (missing.empty()) {
        cout << -1 << '\n';
    } else {
        cout << missing.size() << '\n';
        for (int m : missing) {
            cout << m << ' ';
        }
        cout << '\n';
    }
}

