    vector<pair<int, int>> edges;

    for (int i = 1; i <= n; ++i) {
        dist[i][i] = 0;
    }

    for (int i = 0; i < m; ++i) {
        int x, y, l;
        cin >> x >> y >> l;
        dist[x][y] = dist[y][x] = l;
        edges.emplace_back(x, y);
    }

    floydWarshall(dist, edges);

    map<pair<int, int>, int> edgeFrequency;

    for (int s = 1; s <= n; ++s) {
        for (int t = 1; t <= n; ++t) {
            if (s == t || dist[s][t] == INF) continue;

            int u = s, v = t;
            while (u != v) {
