int minDeposits(int n, int d, const vector<int>& transactions) {
    long long balance = 0;
    int deposits = 0;

    for (int i = 0; i < n; ++i) {
        balance += transactions[i];

        // Check if balance goes negative and next transaction is 0
        if (balance < 0 && (i == n-1 || transactions[i+1] != 0)) {
            return -1;
        }

        // If balance is negative but next transaction is 0, deposit enough to reach 0
        if (balance < 0 && transactions[i+1] == 0) {
            deposits++;
            balance = 0;
        }

        // Cap balance at d
        if (balance > d) {
            balance = d;
        }
    }

    return deposits;
}

