constexpr double EPS = 1e-6;
constexpr int MAXN = 100;
constexpr double V = 0.1;
constexpr double STEP = 0.01;

double dp[MAXN][MAXN][MAXN];

double calc(double c, double m, double p) {
    if (abs(p) < EPS) return 0;
    if (dp[(int)(c / STEP)][(int)(m / STEP)][(int)(p / STEP)] != -1) return dp[(int)(c / STEP)][(int)(m / STEP)][(int)(p / STEP)];

    double sum = 0;
    for (int i = 0; i <= 100; ++i) {
        for (int j = 0; j <= 100; ++j) {
            double nc = i * STEP;
            double nm = j * STEP;
            if (nc == c && nm == m) continue;
            double np = p;
            if (np <= V) {
                np -= nc;
                nc = 0;
                nm += np;
            } else {
                np -= V;
                nc += V / 2;
                nm += V / 2;
            }
            if (nc < 0 || nm < 0 || np < 0) continue;
            sum += (nc + nm) + calc(nc, nm, np);
        }
    }
    return dp[(int)(c / STEP)][(int)(m / STEP)][(int)(p / STEP)] = 1 + sum / ((c + m) * 100);
}

void solve() {
    memset(dp, -1, sizeof(dp));
    double c, m, p, v;
    cin >> c >> m >> p >> v;
    cout << calc(c, m, p) << '\n';
}

