pair<long long, long long> solve(long long x, long long y, long long z) {
    // Initial calculation without exchange
    long long initial_sasha_coconuts = x / z;
    long long initial_masha_coconuts = y / z;
    long long initial_total = initial_sasha_coconuts + initial_masha_coconuts;

    // Initialize variables to store the result
    long long max_coconuts = initial_total;
    long long min_exchange = 0;

    // Iterate over possible exchanges
    for (long long k = 0; k <= min(x, y); ++k) {
        long long sasha_new_coconuts = (x - k) / z;
        long long masha_new_coconuts = (y + k) / z;
        long long new_total = sasha_new_coconuts + masha_new_coconuts;

        if (new_total > max_coconuts) {
            max_coconuts = new_total;
            min_exchange = k;
        } else if (new_total == max_coconuts && k < min_exchange) {
            min_exchange = k;
        }
    }

    return {max_coconuts, min_exchange};
}

