int minSeconds(int n, int pos, int l, int r) {
    // If cursor is already within the segment [l, r], no movement needed
    if (pos >= l && pos <= r) {
        return r - pos;
    }

    // Cost to move to the start of the segment and close tabs to the left
    int moveToLeft = pos - l;
    int closeLeft = l - 1;

    // Cost to move to the end of the segment and close tabs to the right
    int moveToRight = r - pos;
    int closeRight = n - r;

    // Return the minimum of the two scenarios
    return min(moveToLeft + closeLeft, moveToRight + closeRight);
}

