const int MOD = 1e9 + 7;
const int BASE = 29;

long long pow_mod(long long base, long long exp, long long mod) {
    long long result = 1;
    while (exp > 0) {
        if (exp % 2 == 1)
            result = (result * base) % mod;
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

struct RollingHash {
    vector<long long> h, p;
    RollingHash(const string& str) : h(str.size() + 1), p(str.size() + 1) {
        p[0] = 1;
        for (size_t i = 0; i < str.size(); ++i) {
            h[i + 1] = (h[i] * BASE + str[i]) % MOD;
            p[i + 1] = (p[i] * BASE) % MOD;
        }
    }

    long long get_hash(size_t l, size_t r) const {
        return (h[r] - h[l] * p[r - l] % MOD + MOD) % MOD;
    }
};

bool is_beautiful(const string& t, const RollingHash& x, const RollingHash& y, size_t pos) {
    size_t len_x = x.h.size() - 1;
    size_t len_y = y.h.size() - 1;
    size_t n = t.size();
    if (pos + len_x <= n && pos >= len_y) {
        long long hash_x = x.get_hash(0, len_x);
        long long hash_y = y.get_hash(pos, pos + len_y);
        if ((hash_x == hash_y && pos + len_x == n) || (hash_x == hash_y && pos == len_y)) {
            return true;
        }
    }
    if (pos >= len_x && pos + len_y <= n) {
        long long hash_x = x.get_hash(pos, pos + len_x);
        long long hash_y = y.get_hash(0, len_y);
        if ((hash_x == hash_y && pos + len_x == n) || (hash_x == hash_y && pos == len_y)) {
            return true;
        }
    }
    return false;
}

