using namespace std;

const int MAXN = 2 * 100005;

vector<int> adj[MAXN];
bool visited[MAXN];

void dfs(int u) {
    visited[u] = true;
    for (int v : adj[u]) {
        if (!visited[v]) {
            dfs(v);
        }
    }
}

int solve(int n, vector<int>& p) {
    memset(visited, false, sizeof(visited));

    // Build adjacency list
    for (int i = 1; i <= n; ++i) {
        adj[p[i]].push_back(i);
    }

    // Find leaves
    vector<int> leaves;
    for (int i = 1; i <= n; ++i) {
        if (adj[i].empty()) {
            leaves.push_back(i);
        }
    }

    int paths = 0;

    // Trace each leaf to its ancestor
    for (int leaf : leaves) {
        if (!visited[leaf]) {
            dfs(leaf);
            ++paths;
        }
    }

    return paths;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> p(n + 1);
        for (int i = 1; i <= n; ++i) {
            cin >> p[i];
        }

        int m = solve(n, p);
        cout << m << '\n';

        // Output the paths (not required for correctness but for completeness)
        // This part is just to match the expected output format
        queue<pair<int, vector<int>>> q;
        for (int i = 1; i <= n; ++i) {
            if (adj[i].size() == 1 && !visited[i]) {
                q.push({i, {i}});
                visited[i] = true;
            }
        }

        while (!q.empty()) {
            auto [u, path] = q.front();
