vector<pair<int, char>> constraints;
vector<vector<int>> perms;
vector<bool> is_unimodal;

void backtrack(int pos, vector<int>& cur_perm) {
    if (pos == 2 * n) {
        perms.push_back(cur_perm);
        return;
    }
    for (int i = 1; i <= n; ++i) {
        if (!used[i]) {
            used[i] = true;
            cur_perm.push_back(i);
            backtrack(pos + 1, cur_perm);
            cur_perm.pop_back();
            used[i] = false;
        }
    }
}

bool is_valid(const vector<int>& perm) {
    int max_height = 0;
    for (int i = 0; i < 2 * n; ++i) {
        max_height = max(max_height, perm[i]);
        if (max_height != i + 1) {
            break;
        }
    }
    return max_height == n && is_unimodal[perm.back()];
}

bool check_constraints(const vector<int>& perm) {
    for (auto& cons : constraints) {
        int x = perm[cons.first - 1] - 1;
        int y = perm[cons.second - 1] - 1;
        switch (cons.second) {
            case '=': if (x != y) return false; break;
            case '<': if (x >= y) return false; break;
            case '>': if (x <= y) return false; break;
            case '<=': if (x > y) return false; break;
            case '>=': if (x < y) return false; break;
        }
    }
    return true;
}

