        constraints.emplace_back(x, c);
    }

    vector<int> cur_perm;
    backtrack(0, cur_perm);

    for (auto& perm : perms) {
        if (is_valid(perm)) {
            bool valid = true;
            for (auto& cons : constraints) {
                int x = perm[cons.first - 1] - 1;
                int y = perm[cons.second - 1] - 1;
                switch (cons.second) {
                    case '=': if (x != y) { valid = false; break; }
