const int MOD = 998244353;
const int MAXN = 1010;

int n, m;
vector<vector<int>> a;
vector<vector<pair<int, int>>> dp;

inline int mod_add(int x, int y) {
    return (x + y) % MOD;
}

inline int mod_mul(int x, int y) {
    return (long long)x * y % MOD;
}

inline int inv(int x) {
    int res = 1, p = MOD - 2;
    while (p > 0) {
        if (p & 1) res = mod_mul(res, x);
        x = mod_mul(x, x);
        p >>= 1;
    }
    return res;
}

pair<int, int> getNeighbors(int i, int j) {
    pair<int, int> minDist = {MOD, MOD};
    for (int dx = -1; dx <= 1; ++dx) {
        for (int dy = -1; dy <= 1; ++dy) {
            if (dx == 0 && dy == 0) continue;
            int x = i + dx, y = j + dy;
            if (x >= 0 && x < n && y >= 0 && y < m) {
                if (a[x][y] < a[i][j]) {
                    minDist.first = min(minDist.first, dx * dx + dy * dy);
                    minDist.second++;
                }
            }
        }
    }
    return minDist;
}

int dfs(int i, int j) {
    if (dp[i][j].first != -1) return dp[i][j].second;

    auto [minDist, count] = getNeighbors(i, j);
    if (count == 0) {
        dp[i][j] = {0, 0};
        return 0;
    }

    int totalScore = 0;
    for (int dx = -1; dx <= 1; ++dx) {
        for (int dy = -1; dy <= 1; ++dy) {
            if (dx == 0 && dy == 0) continue;
            int x = i + dx, y = j + dy;
            if (x >= 0 && x < n && y >= 0 && y < m && a[x][y] < a[i][j]) {
                totalScore = mod_add(totalScore, mod_mul(mod_mul(dx * dx + dy * dy, dfs(x, y)), inv(count)));
            }
        }
    }

    dp[i][j] = {totalScore, 1};
    return totalScore;
}

