bool is_prime(int x) {
    if (x <= 1) return false;
    if (x == 2) return true;
    if (x % 2 == 0) return false;
    for (int i = 3; i * i <= x; i += 2)
        if (x % i == 0) return false;
    return true;
}

int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int min_removals(vector<int>& a) {
    int n = a.size();
    vector<bool> keep(n, true);

    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (gcd(a[i], a[j]) > 1) {
                keep[i] = keep[j] = false;
            }
        }
    }

    int count = 0;
    for (int i = 0; i < n; ++i) {
        if (!keep[i]) {
            count++;
        } else {
            // Ensure the element is at least 2 and prime
            if (a[i] < 2 || !is_prime(a[i])) {
                count++;
            }
        }
    }
    return count;
}

