void precompute() {
    const int MAXA = 10000000;
    static vector<int> spf(MAXA + 1);
    static vector<int> primes;
    static bool done = false;
    if (done) return;
    done = true;
    for (int i = 2; i <= MAXA; ++i) {
        if (spf[i] == 0) {
            spf[i] = i;
            primes.pb(i);
        }
        for (int p : primes) {
            if (p > spf[i] || (long long)i * p > MAXA) break;
            spf[i * p] = p;
        }
    }
}

ll square_free(ll x) {
    if (x == 1) return 1;
    const int MAXA = 10000000;
    static vector<int> spf(MAXA + 1);
    static bool init = false;
    if (!init) {
        init = true;
        for (int i = 2; i <= MAXA; ++i) {
            if (spf[i] == 0) {
                spf[i] = i;
                for (int j = i; j <= MAXA; j += i) {
                    if (spf[j] == 0) spf[j] = i;
                }
            }
        }
    }
    ll res = 1;
    while (x > 1) {
        int p = spf[x];
        int cnt = 0;
        while (x % p == 0) {
            x /= p;
            cnt ^= 1;
        }
        if (cnt) res *= p;
    }
    return res;
}

