vector<int> inp;
int inp_idx = 0;

vector<int> dfs(int node, vector<vector<int>>& adj, int n) {
    int timer = n;
    vector<int> perm(n + 1, 0);
    perm[node] = timer;
    timer--;
    stack<int> st;
    st.push(node);
    while (!st.empty()) {
        int cur = st.top();
        if (!adj[cur].empty()) {
            int neighbor = adj[cur].back();
            adj[cur].pob();
            st.push(neighbor);
            perm[neighbor] = timer;
            timer--;
        } else {
            st.pop();
        }
    }
    return perm;
}

bool check(int n, const vector<int>& nxt, const vector<int>& perm) {
    stack<int> st;
    st.push(n);
    for (int i = n - 1; i >= 0; --i) {
        while (st.top() < perm[i]) {
            st.pop();
        }
        if (st.top() != perm[nxt[i]]) {
            return false;
        }
        st.push(perm[i]);
    }
    return true;
}

void solve() {
    int n = inp[inp_idx++];
    vector<int> nxt(n);
    for (int i = 0; i < n; ++i) {
        nxt[i] = inp[inp_idx++];
    }
    for (int i = 0; i < n; ++i) {
        if (nxt[i] == -1) {
            nxt[i] = i + 1;
        } else {
            nxt[i] = nxt[i] - 1;
