using namespace std;

int solve(int n, int t) {
    vector<vector<double>> pyramid(n);
    for (int i = 0; i < n; ++i) {
        pyramid[i].resize(i + 1, 0.0);
    }

    // Top glass starts with 1 unit of champagne
    pyramid[0][0] = 1.0;

    queue<pair<int, int>> q;
    q.push({0, 0});

    while (!q.empty() && t > 0) {
        int x = q.front().first;
        int y = q.front().second;
        q.pop();

        double extra = pyramid[x][y] - 1.0;
        if (extra > 0) {
            pyramid[x][y] = 1.0;

            if (x + 1 < n) {
                pyramid[x + 1][y] += extra / 2.0;
                if (pyramid[x + 1][y] == 1.0) {
                    q.push({x + 1, y});
                }

                if (y + 1 <= x) {
                    pyramid[x + 1][y + 1] += extra / 2.0;
                    if (pyramid[x + 1][y + 1] == 1.0) {
                        q.push({x + 1, y + 1});
                    }
                }
            }
        }

        --t;
    }

    int count = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j <= i; ++j) {
            if (pyramid[i][j] >= 1.0) {
                ++count;
            }
        }
    }

    return count;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, t;
    cin >> n >> t;

    cout << solve(n, t) << endl;

