const int MAXN = 2 * 100000 + 1;
bool is_prime[MAXN];
int parent[MAXN], color[MAXN];

void sieve_of_eratosthenes(int max_val) {
    fill(is_prime, is_prime + max_val + 1, true);
    is_prime[0] = is_prime[1] = false;
    for (int i = 2; i <= max_val; ++i) {
        if (is_prime[i]) {
            for (int j = i * i; j <= max_val; j += i) {
                is_prime[j] = false;
            }
        }
    }
}

void bfs_coloring(vector<vector<int>>& adj, int start) {
    queue<int> q;
    q.push(start);
    color[start] = 1;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : adj[u]) {
            if (color[v] == -1) {
                color[v] = color[u] ^ 1;
                q.push(v);
            } else if (color[v] == color[u]) {
                cout << "IMPOSSIBLE\n";
                exit(0);
            }
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    sieve_of_eratosthenes(MAXN);

    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;

        vector<vector<int>> adj(n + 1);

        for (int u = 1; u <= n; ++u) {
            for (int v = u + 1; v <= n; ++v) {
                int x = u ^ v;
                if (is_prime[x]) {
                    adj[u].push_back(v);
                    adj[v].push_back(u);
                }
            }
