void solve(int n, int m, const vector<vector<int>>& grid, int t, const vector<pair<pair<int, int>, pair<int, int>>>& queries) {
    vector<vector<int>> dp(n, vector<int>(m, 0));

    // Compute DP table
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            if (grid[i][j] == 1) {
                int up = (i > 0) ? dp[i-1][j] : 0;
                int left = (j > 0) ? dp[i][j-1] : 0;
                int diag = (i > 0 && j > 0) ? dp[i-1][j-1] : 0;
                dp[i][j] = min({up, left, diag}) + 1;
            }
        }
    }

    for (const auto& q : queries) {
        int x1 = q.first.first - 1, y1 = q.first.second - 1;
        int x2 = q.second.first - 1, y2 = q.second.second - 1;

        int width = min(y2 - y1 + 1, dp[x2][y2]);
        cout << width << endl;
    }
}

