bool is_bad(const vector<int>& arr, int start, int end) {
    int m = (start + end) / 2;
    vector<int> sorted(arr.begin() + start, arr.begin() + end + 1);
    sort(sorted.begin(), sorted.end());
    return sorted[m] == arr[m];
}

int count_ways(int idx, vector<int>& state) {
    if (idx == n) {
        for (int i = 0; i < n; ++i) {
            if (state[i] == -1) {
                // Check all possible values for unknown positions
                bool good = true;
                for (int len = 3; len <= n; len += 2) {
                    for (int start = i; start + len - 1 < n; ++start) {
                        if (is_bad(state, start, start + len - 1)) {
                            good = false;
                            break;
                        }
                    }
                    if (!good) break;
                }
                if (!good) return 0;
            }
        }
        return 1;
    }
    if (dp[idx][state[idx]] != -1) return dp[idx][state[idx]];

    int ans = 0;
    for (int val = 1; val <= n; ++val) {
        if ((state[idx] == -1 || state[idx] == val) && 
            (idx == 0 || p[idx - 1] != val) && 
            (idx == n - 1 || p[idx + 1] != val)) {
            state[idx] = val;
            ans = (ans + count_ways(idx + 1, state)) % MOD;
            state[idx] = -1;
        }
    }

    dp[idx][state[idx]] = ans;
    return ans;
}

