    int max_height = *max_element(heights.begin(), heights.end());
    int min_height = *min_element(heights.begin(), heights.end());

    auto max_iter = find(heights.begin(), heights.end(), max_height);
    auto min_iter = find(heights.begin(), heights.end(), min_height);

    int max_index = distance(heights.begin(), max_iter);
    int min_index = distance(heights.begin(), min_iter);

