        long long temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int count_pairs(long long c, long long d, long long x) {
    int count = 0;
    for (long long g = 1; g * g <= x; ++g) {
        if (x % g == 0) {
            long long k = x / g + d;
            if (k % c == 0) {
                k /= c;
                long long sqrt_k = static_cast<long long>(sqrt(k));
                for (long long i = 1; i <= sqrt_k; ++i) {
                    if (k % i == 0) {
                        long long j = k / i;
                        if (gcd(i, j) == 1) {
                            ++count;
                            if (i != j) ++count;
                        }
                    }
                }
            }
        }
    }
    return count;
}

