#include <bits/stdc++.h>
using namespace std;

const int MAXN = 2 * 100005;
vector<int> adj[MAXN];
unordered_set<int> reachable[MAXN];

void dfs(int u, int p, int d, vector<int>& depths, vector<vector<int>>& paths) {
    depths[u] = d;
    paths[d].push_back(u);
    for (int v : adj[u]) {
        if (v == p) continue;
        dfs(v, u, d + 1, depths, paths);
    }
}

bool isValidMerge(int u, int v, const unordered_set<int>& s1, const unordered_set<int>& s2) {
    for (int x : s1) {
        for (int y : s2) {
            if (x != u && y != u && adj[x][y] != u) return false;
        }
    }
    return true;
}

int minEdgesToPath(int n, vector<pair<int, int>>& edges) {
    for (auto& e : edges) {
        adj[e.first].push_back(e.second);
        adj[e.second].push_back(e.first);
    }

    vector<int> depths(n + 1, 0);
    vector<vector<int>> paths(MAXN);
    dfs(1, 0, 0, depths, paths);

    auto comp = [&](pair<int, int> a, pair<int, int> b) {
        return a.first + a.second > b.first + b.second;
    };
    priority_queue<pair<int, int>, vector<pair<int, int>>, decltype(comp)> pq(comp);
    for (int i = 0; i <= n; ++i) {
        for (size_t j = 0; j < paths[i].size(); ++j) {
            int u = paths[i][j];
            reachable[u] = {};
            for (int v : adj[u]) {
                if (v == 0 || v == u) continue;
                reachable[u].insert(depths[v]);
            }
        }
    }

    while (adj.size() > 2) {
        int u = 0, v = 0, maxLen = 0;
        for (int i = 1; i <= n; ++i) {
            for (int j = i + 1; j <= n; ++j) {
                if (!isValidMerge(i, j, reachable[i], reachable[j])) continue;
                int len = depths[i] + depths[j] - 1;
                if (len > maxLen) {
                    maxLen = len;
                    u = i;
                    v = j;
                }
            }
        }
        if (u == 0) break;
        // Remove u and v from the graph
        for (int x : adj[u]) {
            adj[x].erase(find(adj[x].begin(), adj[x].end(), u));
        }
        for (int x : adj[v]) {
            adj[x].erase(find(adj[x].begin(), adj[x].end(), v));
        }
        adj.erase(adj.begin() + u);
        adj.erase(adj.begin() + v - 1); // Adjust index after removal
    }

    if (adj.size() == 2) {
        int u = adj.begin()->first, v = adj.begin()->second;
        return depths[u] + depths[v] - 1;
    } else {
        return -1;
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<pair<int, int>> edges(n - 1);
    for (int i = 0; i < n - 1; ++i) {
        cin >> edges[i].first >> edges[i].second;
    }

    cout << minEdgesToPath(n, edges) << '\n';

    return 0;
}

