void solve() {
    int n;
    cin >> n;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }
    string s;
    cin >> s;

    vector<int> door_open_time(n + 1, INT_MAX);
    for (int i = 0; i < n; ++i) {
        if (a[i] >= 0) {
            door_open_time[a[i]] = min(door_open_time[a[i]], i);
        }
    }

    vector<int> ans(n);
    for (int i = 0; i < n; ++i) {
        bool has_key = false;
        int pos = 1;
        int time = 0;

        while (pos <= n) {
            // Wait for door to open if not already open
            while (time < door_open_time[pos]) {
                ++time;
            }

            // Pick up key if available
            if (!has_key && s[pos - 1] == '1') {
                has_key = true;
            }

            // Drop key if needed
            if (has_key && s[pos - 1] == '0') {
                has_key = false;
            }

            // Move to next room
            if (pos < n) {
                if (has_key || pos == 1) {
                    ++pos;
                    --time; // Consume key on move
                } else {
                    --pos;
                }
            }

            ++time;
        }

        ans[i] = time - 1; // Adjust for extra increment at the end
    }

    for (int x : ans) {
        cout << x << " ";
    }
    cout << endl;
}

